 47	func (s *Store) Validate(metricID string) (*Definition, *docgraph.Document, error) {
 48		doc, err := s.loadMetricArtifact(metricID)
 49		if err != nil {
 50			return nil, nil, err
 51		}
 52		def, err := s.LoadDefinition(metricID)
 53		if err != nil {
 54			return nil, nil, err
 55		}
 56		if def.MetricID != metricID {
 57			return nil, nil, fmt.Errorf("metric definition %q does not target %q", def.DefinitionID, metricID)
 58		}
 59		if len(def.Command) == 0 {
 60			return nil, nil, fmt.Errorf("metric definition %q has no command", def.DefinitionID)
 61		}
 62		if def.Comparison == "" {
 63			def.Comparison = ComparisonLowerIsBetter
 64		}
 65		switch def.Comparison {
 66		case ComparisonLowerIsBetter, ComparisonHigherIsBetter:
 67		default:
 68			return nil, nil, fmt.Errorf("metric definition %q has invalid comparison %q", def.DefinitionID, def.Comparison)
 69		}
 70		return &def, doc, nil
 71	}
 72	
 73	func (s *Store) Run(ctx context.Context, metricID string) (HistoryRecord, error) {
 74		def, _, err := s.Validate(metricID)
 75		if err != nil {
 76			return HistoryRecord{}, err
 77		}
 78		rec, err := s.execStore.Run(ctx, def.DefinitionID)
 79		if err != nil {
 80			return HistoryRecord{}, err
 81		}
 82		return metricHistoryFromExec(rec)
 83	}
 84	
 85	func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
 86		history, err := s.History(metricID)
 87		if err != nil {
 88			return HistoryRecord{}, ComparisonResult{}, err
 89		}
 90		if len(history) == 0 {
 91			return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
 92		}
 93		if _, err := singleHistoryUnit(metricID, history); err != nil {
 94			return HistoryRecord{}, ComparisonResult{}, err
 95		}
 96		current := history[len(history)-1]
 97		target, err := selectComparisonTarget(history, against)
 98		if err != nil {
 99			return HistoryRecord{}, ComparisonResult{}, err
100		}
101		result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
102		current.Comparison = result
103		return current, result, nil
104	}
105	
106	func (s *Store) Trend(metricID string) (TrendSummary, error) {
107		history, err := s.History(metricID)
108		if err != nil {
109			return TrendSummary{}, err
110		}
111		if len(history) == 0 {
112			return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
113		}
114		unit, err := singleHistoryUnit(metricID, history)
115		if err != nil {
116			return TrendSummary{}, err
117		}
118		summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: unit, UpdatedAt: history[len(history)-1].ObservedAt}
119		var sum float64
120		for _, rec := range history {
121			if rec.Value < summary.Min {
122				summary.Min = rec.Value
123			}
124			if rec.Value > summary.Max {
125				summary.Max = rec.Value
126			}
127			sum += rec.Value
128			summary.UpdatedAt = rec.ObservedAt
129		}
130		summary.Count = len(history)
131		summary.Average = sum / float64(len(history))
132		return summary, nil
133	}
134	
135	// GroupedHistory returns history rows partitioned by unit while preserving
136	// the observed order within each unit group.
137	func (s *Store) GroupedHistory(metricID string) ([]HistoryGroup, error) {
138		history, err := s.History(metricID)
139		if err != nil {
140			return nil, err
141		}
142		return groupHistoryByUnit(history), nil
143	}
