145	func (s *Store) LoadDefinition(metricID string) (Definition, error) {
146		if s.execStore == nil {
147			return Definition{}, fmt.Errorf("metric store is not initialized")
148		}
149		defs, err := s.execStore.ListDefinitions(metricID)
150		if err != nil {
151			return Definition{}, err
152		}
153		var (
154			best  Definition
155			found bool
156		)
157		for _, def := range defs {
158			if def.ID == "" {
159				continue
160			}
161			mapped, err := metricDefinitionFromExec(def)
162			if err != nil {
163				return Definition{}, err
164			}
165			if mapped.MetricID != metricID || !mapped.Active {
166				continue
167			}
168			if !found || mapped.CreatedAt.After(best.CreatedAt) || (mapped.CreatedAt.Equal(best.CreatedAt) && mapped.DefinitionID > best.DefinitionID) {
169				best = mapped
170				found = true
171			}
172		}
173		if !found {
174			return Definition{}, fmt.Errorf("metric definition for %q not found", metricID)
175		}
176		if best.DefinitionID == "" {
177			return Definition{}, fmt.Errorf("metric definition for %q is missing definition_id", metricID)
178		}
179		return best, nil
180	}
181	
182	func (s *Store) History(metricID string) ([]HistoryRecord, error) {
183		if s.execStore == nil {
184			return []HistoryRecord{}, fmt.Errorf("metric store is not initialized")
185		}
186		records, err := s.execStore.History(metricID, "")
187		if err != nil {
188			return nil, err
189		}
190		out := make([]HistoryRecord, 0, len(records))
191		for _, rec := range records {
192			mapped, err := metricHistoryFromExec(rec)
193			if err != nil {
194				return nil, err
195			}
196			if mapped.MetricID == metricID {
197				out = append(out, mapped)
198			}
199		}
200		return out, nil
201	}
