66	func metricArtifactID(ids []string) string {
67		if len(ids) == 0 {
68			return ""
69		}
70		for _, id := range ids {
71			if len(id) >= 4 && id[:4] == "MET-" {
72				return id
73			}
74		}
75		return ids[0]
76	}

